'use client';

import { useState, useMemo } from 'react';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import type { LogEntry, LogLevel } from '@/types';
import { cn } from '@/lib/utils';
import { ScrollArea } from '@/components/ui/scroll-area';

interface LogViewerProps {
  logs: LogEntry[];
}

const levelBadgeVariant: Record<LogLevel, 'destructive' | 'secondary' | 'default' | 'outline'> = {
  ERROR: 'destructive',
  WARN: 'default',
  INFO: 'secondary',
  DEBUG: 'outline',
  UNKNOWN: 'outline',
};

const levelColorClass: Record<LogLevel, string> = {
    ERROR: 'text-destructive',
    WARN: 'text-primary',
    INFO: 'text-accent-foreground',
    DEBUG: 'text-muted-foreground',
    UNKNOWN: 'text-muted-foreground',
};


export function LogViewer({ logs }: LogViewerProps) {
  const [searchTerm, setSearchTerm] = useState('');

  const filteredLogs = useMemo(() => {
    if (!searchTerm) return logs;
    return logs.filter((log) =>
      log.originalLine.toLowerCase().includes(searchTerm.toLowerCase())
    );
  }, [logs, searchTerm]);

  return (
    <div className="space-y-4">
      <Input
        placeholder="Search logs..."
        value={searchTerm}
        onChange={(e) => setSearchTerm(e.target.value)}
        className="max-w-sm"
      />
      <ScrollArea className="h-[600px] rounded-md border">
        <Table>
          <TableHeader className="sticky top-0 bg-card z-10">
            <TableRow>
              <TableHead className="w-[180px]">Timestamp</TableHead>
              <TableHead className="w-[100px]">Level</TableHead>
              <TableHead>Message</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {filteredLogs.map((log) => (
              <TableRow key={log.id}>
                <TableCell className="font-code text-xs text-muted-foreground">
                  {log.timestamp || 'N/A'}
                </TableCell>
                <TableCell>
                  <Badge variant={levelBadgeVariant[log.level]}>{log.level}</Badge>
                </TableCell>
                <TableCell className={cn("font-code text-xs", levelColorClass[log.level])}>
                  {log.message}
                </TableCell>
              </TableRow>
            ))}
             {filteredLogs.length === 0 && (
                <TableRow>
                    <TableCell colSpan={3} className="h-24 text-center">
                        No results found.
                    </TableCell>
                </TableRow>
            )}
          </TableBody>
        </Table>
      </ScrollArea>
    </div>
  );
}
