// src/ai/flows/detect-log-anomalies.ts
'use server';
/**
 * @fileOverview An AI agent for detecting and summarizing log anomalies.
 *
 * - detectLogAnomalies - A function that handles the log anomaly detection process.
 * - DetectLogAnomaliesInput - The input type for the detectLogAnomalies function.
 * - DetectLogAnomaliesOutput - The return type for the detectLogAnomalies function.
 */

import {ai} from '@/ai/genkit';
import {z} from 'genkit';

const DetectLogAnomaliesInputSchema = z.object({
  logData: z
    .string()
    .describe("Log data as a string."),
});
export type DetectLogAnomaliesInput = z.infer<typeof DetectLogAnomaliesInputSchema>;

const DetectLogAnomaliesOutputSchema = z.object({
  summary: z.string().describe('A human-readable summary of the detected anomalies and potential security threats.'),
});
export type DetectLogAnomaliesOutput = z.infer<typeof DetectLogAnomaliesOutputSchema>;

export async function detectLogAnomalies(input: DetectLogAnomaliesInput): Promise<DetectLogAnomaliesOutput> {
  return detectLogAnomaliesFlow(input);
}

const prompt = ai.definePrompt({
  name: 'detectLogAnomaliesPrompt',
  input: {schema: DetectLogAnomaliesInputSchema},
  output: {schema: DetectLogAnomaliesOutputSchema},
  prompt: `You are a security analyst specializing in detecting anomalies and security threats in log data.

You will analyze the provided log data and identify any unusual patterns, potential errors, and security threats.

Based on your analysis, you will generate a concise, human-readable summary of the detected anomalies and potential security threats.

Log Data: {{{logData}}}
`,
});

const detectLogAnomaliesFlow = ai.defineFlow(
  {
    name: 'detectLogAnomaliesFlow',
    inputSchema: DetectLogAnomaliesInputSchema,
    outputSchema: DetectLogAnomaliesOutputSchema,
  },
  async input => {
    const {output} = await prompt(input);
    return output!;
  }
);
