'use client';

import { useMemo } from 'react';
import type { LogEntry } from '@/types';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import {
  ChartContainer,
  ChartTooltip,
  ChartTooltipContent,
} from '@/components/ui/chart';
import { Bar, BarChart, CartesianGrid, XAxis, YAxis } from 'recharts';

interface LogLevelChartProps {
  logs: LogEntry[];
}

const chartConfig = {
  count: {
    label: 'Count',
  },
  ERROR: {
    label: 'Error',
    color: 'hsl(var(--destructive))',
  },
  WARN: {
    label: 'Warning',
    color: 'hsl(var(--primary))',
  },
  INFO: {
    label: 'Info',
    color: 'hsl(var(--accent))',
  },
  DEBUG: {
    label: 'Debug',
    color: 'hsl(var(--muted-foreground))',
  },
  UNKNOWN: {
    label: 'Unknown',
    color: 'hsl(var(--border))',
  },
} as const;

export function LogLevelChart({ logs }: LogLevelChartProps) {
  const data = useMemo(() => {
    const counts = logs.reduce((acc, log) => {
      acc[log.level] = (acc[log.level] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    return Object.entries(counts)
      .map(([name, value]) => ({
        name,
        count: value,
        fill: chartConfig[name as keyof typeof chartConfig]?.color || chartConfig.UNKNOWN.color,
      }))
      .sort((a, b) => b.count - a.count);
  }, [logs]);

  return (
    <Card>
      <CardHeader>
        <CardTitle>Log Level Distribution</CardTitle>
        <CardDescription>A visual breakdown of log entries by their severity level.</CardDescription>
      </CardHeader>
      <CardContent>
        <ChartContainer config={chartConfig} className="min-h-[200px] w-full h-80">
          <BarChart accessibilityLayer data={data} layout="vertical" margin={{ left: 10 }}>
            <CartesianGrid horizontal={false} />
            <YAxis
              dataKey="name"
              type="category"
              tickLine={false}
              tickMargin={10}
              axisLine={false}
              tickFormatter={(value) => chartConfig[value as keyof typeof chartConfig]?.label || value}
            />
            <XAxis dataKey="count" type="number" hide />
            <ChartTooltip
              cursor={false}
              content={<ChartTooltipContent
                labelKey="count"
                indicator="dot"
              />}
            />
            <Bar dataKey="count" layout="vertical" radius={5} />
          </BarChart>
        </ChartContainer>
      </CardContent>
    </Card>
  );
}
